        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found at external_services_path."}
    with open(mailbox_path, "r") as f:
        data = json.load(f)

    emails = data.get("emails", [])
    sent_emails = [e for e in emails if e.get("folder", "").lower() == "sent"]

    candidate = None
    for email in sent_emails:
        if "ar@cascadeit.com" in (email.get("to_addr") or "").lower():
            candidate = email
            break

    if candidate is None:
        return {"pass": False, "score": 0.0, "feedback": "No sent email found to ar@cascadeit.com. Expected a dispute email regarding credit memo CM-38720."}

    def normalize(s):
        s = str(s).lower()
        s = re.sub(r'\s+', ' ', s)
        s = s.replace('\u2014', '-').replace('\u2013', '-')
        s = s.replace(',', '')
        return s.strip()

    body = normalize(candidate.get("body_text") or "")

    # Expected full body (from rubric draft), broken into complete sentences for verification:
    # "Dear Brian Choi, We received credit memo CM-38720 dated 2025 for $2,000.00.
    #  This amount exceeds the original invoice INV-38720 totaling $1,950.00.
    #  We are unable to apply this credit until clarification is received.
    #  Please provide a corrected credit memo or written explanation.
    #  Meridian Partners Accounts Payable"
    checks = {
        "greeting (Dear Brian Choi)":
            "dear brian choi" in body,
        "cm receipt sentence (CM-38720 dated [2025-09-11 or 09/11/2025] for $2,000.00)":
            ("we received credit memo cm-38720 dated 2025-09-11 for $2000.00" in body or
             "we received credit memo cm-38720 dated 09/11/2025 for $2000.00" in body),
        "exceeds invoice sentence (INV-38720 totaling $1,950.00)":
            "this amount exceeds the original invoice inv-38720 totaling $1950.00" in body,
        "unable to apply sentence":
            "we are unable to apply this credit until clarification is received" in body,
        "corrected cm or explanation sentence":
            "please provide a corrected credit memo or written explanation" in body,
        "sign-off (Meridian Partners Accounts Payable)":
            "meridian partners accounts payable" in body
    }


    failed = [k for k, v in checks.items() if not v]
    passed_count = len(checks) - len(failed)
    score = round(passed_count / len(checks), 2)

    if not failed:
        return {"pass": True, "score": 1.0, "feedback": f"Sent email to ar@cascadeit.com passes all {len(checks)} checks. Correct dispute email sent for CM-38720."}
    else:
        return {"pass": False, "score": score, "feedback": f"Sent email to ar@cascadeit.com found but {len(failed)}/{len(checks)} checks failed. Missing: {failed}. Body: {(candidate.get('body_text') or '')[:500]}"}

