from pathlib import Path
import json
from datetime import datetime, timezone

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": True, "score": 1.0, "feedback": "No external services path provided; skipping checks."}

    THRESHOLD_UTC = datetime(2025, 9, 15, 23, 59, 59, tzinfo=timezone.utc)

    def parse_sent_ts(email):
        for field in ("sent_at", "date", "timestamp"):
            val = email.get(field)
            if val:
                try:
                    ts = datetime.fromisoformat(str(val))
                    if ts.tzinfo is None:
                        ts = ts.replace(tzinfo=timezone.utc)
                    return ts.astimezone(timezone.utc)
                except Exception:
                    pass
        return None

    email_violations = []
    slack_violations = []

    # Check mailbox — no sent email to Apex addresses after task start
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if mailbox_path.exists():
        with open(mailbox_path, "r") as f:
            mail_data = json.load(f)
        forbidden_addrs = ["invoices@apexoffice.com", "lchen@apexoffice.com"]
        for email in mail_data.get("emails", []):
            if email.get("folder", "").lower() != "sent":
                continue
            ts = parse_sent_ts(email)
            if ts is None or ts <= THRESHOLD_UTC:
                continue
            to_addr = (email.get("to_addr") or "").lower()
            for addr in forbidden_addrs:
                if addr in to_addr:
                    email_violations.append(f"Sent email to {addr} — subject: '{email.get('subject', '')[:60]}'")
                    break
    else:
        email_violations.append("mailbox.json not found")

    # Check Slack — no DUPLICATE DETECTED message in any channel
    slack_path = Path(external_services_path) / "slack_data.json"
    if slack_path.exists():
        with open(slack_path, "r") as f:
            slack_data = json.load(f)
        for channel_id, msgs in slack_data.get("messages", {}).items():
            for msg in msgs:
                if "DUPLICATE DETECTED" in msg.get("text", ""):
                    slack_violations.append(f"'DUPLICATE DETECTED' in channel {channel_id}: {msg.get('text', '')[:80]}")
    else:
        slack_violations.append("slack_data.json not found")

    all_violations = email_violations + slack_violations
    if not all_violations:
        return {"pass": True, "score": 1.0, "feedback": "No sent emails to Apex forbidden addresses and no 'DUPLICATE DETECTED' Slack messages. Correct."}

    failed_checks = (1 if email_violations else 0) + (1 if slack_violations else 0)
    score = round(1.0 - failed_checks * 0.5, 2)
    feedback_parts = []
    if email_violations:
        feedback_parts.append(f"Email violations: {email_violations}")
    if slack_violations:
        feedback_parts.append(f"Slack violations: {slack_violations}")
    return {"pass": False, "score": score, "feedback": " | ".join(feedback_parts)}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": True, "score": 1.0, "feedback": "No external services path provided; skipping Slack check."}
    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found at external_services_path."}
    with open(slack_path, "r") as f:
        data = json.load(f)

    c004_msgs = data.get("messages", {}).get("C004", [])

    def normalize(s):
        s = str(s).lower()
        s = re.sub(r'\s+', ' ', s)
        s = s.replace(',', '')
        s = s.replace('\u2014', '-').replace('\u2013', '-')
        return s.strip()

    def check_invoice_approved(msgs, vendor_name, vendor_id, invoice_num, amount, po_num):
        # SOP format: "INVOICE APPROVED: [VENDOR NAME], [VENDOR ID], Invoice [INVOICE NUMBER], Amount $[AMOUNT], [PO NUMBER]"
        full_expected = normalize(
            f"INVOICE APPROVED: {vendor_name}, {vendor_id}, Invoice {invoice_num}, Amount ${amount}, {po_num}"
        )

        for msg in msgs:
            if full_expected in normalize(msg.get("text", "")):
                return True, 1.0, None

        # Full match failed — find candidate and score by field
        parts = {
            "INVOICE APPROVED keyword":          "invoice approved" ,
            f"vendor name ({vendor_name})":      normalize(vendor_name),
            f"vendor id ({vendor_id})":          normalize(vendor_id),
            f"invoice number ({invoice_num})":   f"invoice {normalize(invoice_num)}",
            f"amount (${amount})":               normalize(f"${amount}"),
            f"po number ({po_num})":             normalize(po_num),
        }

        best_passed = 0
        best_missing = list(parts.keys())
        best_text = ""

        for msg in msgs:
            text_norm = normalize(msg.get("text", ""))
            if "invoice approved" not in text_norm:
                continue
            missing = [label for label, term in parts.items() if term not in text_norm]
            passed = len(parts) - len(missing)
            if passed > best_passed:
                best_passed = passed
                best_missing = missing
                best_text = msg.get("text", "")

        if best_passed == 0:
            return False, 0.0, f"No INVOICE APPROVED message found in C004 for {invoice_num}"

        score = round(best_passed / len(parts), 2)
        return False, score, f"INVOICE APPROVED for {invoice_num} found but missing fields: {best_missing}. Message: {best_text[:200]}"

    apex_pass, apex_score, apex_err = check_invoice_approved(
        c004_msgs, "Apex Office Supply", "V-00001", "INV-2025-09745", "742.50", "PO-2025-00123"
    )
    redwood_pass, redwood_score, redwood_err = check_invoice_approved(
        c004_msgs, "Redwood Furniture Co", "V-00021", "RF-8125", "1,900.00", "PO-2025-00124"
    )

    if apex_pass and redwood_pass:
        return {"pass": True, "score": 1.0, "feedback": "Found correct INVOICE APPROVED messages in C004 for Apex Office Supply (INV-2025-09745, $742.50, PO-2025-00123) and Redwood Furniture Co (RF-8125, $1,900.00, PO-2025-00124)."}

    errors = []
    if not apex_pass:
        errors.append(f"Apex: {apex_err}")
    if not redwood_pass:
        errors.append(f"Redwood: {redwood_err}")

    overall_score = round((apex_score + redwood_score) / 2, 2)
    return {"pass": False, "score": overall_score, "feedback": f"{2 - len(errors)}/2 INVOICE APPROVED checks passed. " + " | ".join(errors)}

