from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "vendor_master.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File vendor_master.xlsx not found at {file_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path))
        sheet_name = next((n for n in wb.sheetnames if "vendor" in n.lower()), None)
        if sheet_name is None:
            return {"pass": False, "score": 0.0, "feedback": f"No vendor sheet found in vendor_master.xlsx. Sheets: {wb.sheetnames}"}
        ws = wb[sheet_name]
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open vendor_master.xlsx: {e}"}


    expected_values = [
        "V-00003",
        "Pinnacle Print Services",
        "58-3456789",
        "45 Press Ln Marietta GA 30060",
        "Brian Matthews",
        "bmatthews@pinnacleprint.com",
        "(336) 555-0291",
        "Net 30",
        "Truliant Federal Credit Union",
        "253175494",
        "0082-1147-3355",
        "Yes",
        "NEC",
        "Active",
        "2023-04-01",
        "0"
    ]

    row_num = 4
    row_data = []
    for col in range(1, ws.max_column + 1):
        cell_val = ws.cell(row=row_num, column=col).value
        row_data.append(cell_val)

    if not row_data or all(v is None for v in row_data):
        return {"pass": False, "score": 0.0, "feedback": f"Row {row_num} is empty in vendor_master.xlsx"}

    def normalize(val):
        if val is None:
            return ""
        s = str(val).strip()
        # Handle dates that might be datetime objects
        if hasattr(val, 'strftime'):
            s = val.strftime('%Y-%m-%d')
        # Remove trailing .0 for integers stored as floats
        if re.match(r'^\d+\.0$', s):
            s = s[:-2]
        return s

    def values_match(actual, expected):
        a = normalize(actual).lower()
        e = expected.strip().lower()
        if a == e:
            return True
        # Try numeric comparison with tolerance
        try:
            a_num = float(a)
            e_num = float(e)
            if e_num == 0:
                return abs(a_num) < 0.01
            return abs(a_num - e_num) / max(abs(e_num), 1e-9) < 0.05
        except (ValueError, TypeError):
            pass
        # Try removing all whitespace and comparing
        if re.sub(r'\s+', '', a) == re.sub(r'\s+', '', e):
            return True
        return False

    mismatches = []
    matched = 0
    for i, expected in enumerate(expected_values):
        if i < len(row_data):
            actual = row_data[i]
            if values_match(actual, expected):
                matched += 1
            else:
                mismatches.append(f"Column {i+1}: expected '{expected}', got '{normalize(actual)}'")
        else:
            mismatches.append(f"Column {i+1}: expected '{expected}', but column does not exist")

    total = len(expected_values)
    score = matched / total if total > 0 else 0.0

    if len(mismatches) == 0:
        return {"pass": True, "score": 1.0, "feedback": f"Row 4 in vendor_master.xlsx matches all {total} expected values: {[normalize(v) for v in row_data[:total]]}"}
    else:
        return {"pass": False, "score": score, "feedback": f"Row 4 in vendor_master.xlsx has {len(mismatches)} mismatches out of {total} columns. Mismatches: {'; '.join(mismatches)}"}

