import json
import re

def verify(workspace_path, external_services_path=None):
    slack_path = None
    for candidate in filter(None, [
        Path(external_services_path) / "slack_data.json" if external_services_path else None,
        Path(workspace_path) / "slack_data.json",
    ]):
        if candidate.exists():
            slack_path = candidate
            break

    if slack_path is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find slack_data.json."}

    try:
        with open(slack_path, "r", encoding="utf-8") as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error reading slack_data.json: {e}"}

    messages = slack_data.get("messages", {}).get("C006", [])
    if not messages:
        return {"pass": False, "score": 0.0, "feedback": "No messages found in #vendor-management (C006)."}

    def normalize(s):
        s = str(s).lower()
        s = re.sub(r'\s+', ' ', s)
        s = s.replace(',', '')
        s = s.replace('\u2014', '-').replace('\u2013', '-')
        return s.strip()

    # SOP format: "BANK CHANGE REQUEST: Pinnacle Print Services, V-00003, Requested by Brian Matthews, Email bmatthews@pinnacleprintsvc.com"
    full_expected = normalize(
        "BANK CHANGE REQUEST: Pinnacle Print Services, V-00003, Requested by Brian Matthews, Email bmatthews@pinnacleprintsvc.com"
    )

    parts = {
        "BANK CHANGE REQUEST keyword":          "bank change request",
        "vendor name (Pinnacle Print Services)": "pinnacle print services",
        "vendor id (V-00003)":                  "v-00003",
        "contact name (Brian Matthews)":        "brian matthews",
        "request email (bmatthews@pinnacleprintsvc.com)": "bmatthews@pinnacleprintsvc.com",
    }

    for msg in messages:
        text_norm = normalize(msg.get("text", ""))
        if full_expected in text_norm:
            return {"pass": True, "score": 1.0, "feedback": f"Found correct BANK CHANGE REQUEST message in C006. Message: {msg.get('text', '')[:300]}"}

    # No exact match — find best candidate and score by field
    best_passed = 0
    best_missing = list(parts.keys())
    best_text = ""

    for msg in messages:
        text_norm = normalize(msg.get("text", ""))
        if "bank change request" not in text_norm:
            continue
        missing = [label for label, term in parts.items() if term not in text_norm]
        passed = len(parts) - len(missing)
        if passed > best_passed:
