        return {"pass": False, "score": 0.0, "feedback": f"File 'vendor_master.xlsx' not found in workspace at {workspace_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
        sheet_name = next((n for n in wb.sheetnames if "vendor" in n.lower()), None)
        if sheet_name is None:
            return {"pass": False, "score": 0.0, "feedback": f"No vendor sheet found in vendor_master.xlsx. Sheets: {wb.sheetnames}"}
        ws = wb[sheet_name]

        cell_value = ws['P21'].value

        # Try to convert to a number for comparison
        if cell_value is None:
            # None could be interpreted as 0 (empty cell) - be generous
            return {"pass": True, "score": 1.0, "feedback": f"Cell P21 is empty/None, which is treated as 0. PASS."}

        try:
            numeric_value = float(cell_value)
        except (ValueError, TypeError):
            # If it's a string like "0" or "0.00" or similar
            stripped = str(cell_value).strip().replace(',', '').replace('$', '')
            try:
                numeric_value = float(stripped)
            except (ValueError, TypeError):
                return {"pass": False, "score": 0.0, "feedback": f"Cell P21 contains '{cell_value}' which cannot be interpreted as a number."}

        # Check if value is 0 (with tolerance: absolute tolerance of 0.01 since expected is 0)
        if abs(numeric_value) <= 0.01:
            return {"pass": True, "score": 1.0, "feedback": f"Cell P21 in vendor_master.xlsx is {cell_value}, which is effectively 0. PASS."}
