    ws = wb[sheet_name]

    # ID 1030 (INV-38720) is at sheet row 31. Search by invoice number as fallback.
    row = 31
    row_values = [ws.cell(row=row, column=c).value for c in range(1, ws.max_column + 1)]

    if str(row_values[3] if len(row_values) > 3 else "") != "INV-38720":
        found_row = None
        for r in range(2, ws.max_row + 1):
            if ws.cell(row=r, column=4).value == "INV-38720":
                found_row = r
                break
        if found_row is None:
            return {"pass": False, "score": 0.0, "feedback": "INV-38720 not found in Invoice Register. Has the row been added?"}
        row = found_row
        row_values = [ws.cell(row=row, column=c).value for c in range(1, ws.max_column + 1)]

    def normalize(val):
        if val is None:
            return ""
        if isinstance(val, (datetime, date)):
            return val.strftime("%Y-%m-%d")
        s = str(val).strip().lower()
        s = re.sub(r'\s+', ' ', s)
        s = s.replace(',', '')
        s = s.replace('\u2014', '-').replace('\u2013', '-')
        return s

    def match(actual, expected):
        if expected == "":
            return actual is None or normalize(actual) == ""
        a = normalize(actual)
        e = normalize(expected)
        if a == e:
            return True
        # Numeric tolerance
        try:
            return abs(float(a.replace('$','')) - float(e.replace('$',''))) / max(abs(float(e.replace('$',''))), 0.001) <= 0.05
        except (ValueError, TypeError):
            return False

    # Expected row: 1030 | V-00020 | Cascade IT Hardware | INV-38720 | 2025-09-02 | PO-2025-00117 |
