        "PO-2025-00117", "PO", "1950.00", "1000-100-6400", "DISP-HOLD",
        "Net 30", "2025-10-02", "T. Okonkwo", "2025-09-03", "", "", "0",
        "Placed on DISP-HOLD on 09/16/2025 - CM-38720.pdf",
    ]

    failures = []
    matched = 0
    for i, exp in enumerate(expected):
        actual = row_values[i] if i < len(row_values) else None
        if match(actual, exp):
            matched += 1
        else:
            failures.append(f"Col {i+1}: expected '{exp}', got '{normalize(actual)}'")

    total = len(expected)
    score = round(matched / total, 2)

    if not failures:
        return {"pass": True, "score": 1.0, "feedback": f"Invoice Register row {row} matches all {total} expected values for INV-38720 (DISP-HOLD)."}
    return {"pass": False, "score": score, "feedback": f"Invoice Register row {row} (INV-38720): {len(failures)}/{total} mismatches — {'; '.join(failures)}"}

